  :root {
    --azul: #1667E8;
    --charcoal: #040417;
    --white: #FFFFFF;
    --font: 'Manrope', sans-serif;
  }

  .container { 
    max-width: 1080px; 
    margin: 0 auto; 
    padding: 0 28px; 
  }

  .eyebrow { 
    display: inline-flex; 
    align-items: center; 
    gap: 10px; 
    font-size: 12px; 
    font-weight: 700; 
    letter-spacing: 3px; 
    text-transform: uppercase; 
    color: #1667E8; 
    margin-bottom: 18px; 
  }

  .eyebrow::before { 
    content: ''; 
    width: 28px; 
    height: 2px; 
    background: var(--azul); 
    border-radius: 2px; 
    flex-shrink: 0; 
  }

  .sl-bg { 
    background: #FFFFFF; 
    padding: 100px 0; 
    color: var(--white); 
    font-family: var(--font);
  }

  h2.disp { 
    font-size: clamp(38px, 4.8vw, 60px); 
