    line-height: 1.04; 
    letter-spacing: -1.5px; 
  }

  h2.disp em { 
    color: var(--azul); 
    font-style: normal; 
  }

  h2.disp.lt { 
    color: #040417; 
  }

  .desc { 
    font-size: 16px; 
    line-height: 1.75; 
    max-width: 540px; 
    margin-top: 14px; 
  }

  .desc.lt { 
    color: #333333; 
  }

  /* WHO SECTION CARDS & ANIMATION */
  .who-grid { 
    display: grid; 
