    gap: 20px; 
    margin-top: 52px; 
  }

  .wcard { 
    background: #F4F5F9; 
    border-radius: 12px; 
    padding: 32px 26px; 
    border: 1px solid rgba(4,4,23,0.10); 
    transition: box-shadow .2s, transform .2s; 
    position: relative; 
    overflow: hidden; 
    text-align: left;
  }

  .wcard::after { 
    content: ''; 
    position: absolute; 
    bottom: 0; 
    left: 0; 
    right: 0; 
    height: 3px; 
    background: var(--azul); 
    transform: scaleX(0); 
    transform-origin: left; 
    transition: transform .3s; 
  }

  .wcard:hover { 
    transform: translateY(-5px); 
    box-shadow: 0 20px 44px rgba(4,4,23,.10); 
  }

  .wcard:hover::after { 
    transform: scaleX(1); 
